// ═══ CONVERSATION MEMORY ═══
// In production: load from Redis by session_id
// For now: stateless per turn (each turn is independent)
const s = $input.first().json;

// Build conversation context from available data
const memory = {
  session_id: s.session_id,
  business_id: s.business_id,
  turns: [],
  collected_data: {},
  last_intent: 'unknown',
  last_emotion: 'neutral'
};

// Add current turn
memory.turns.push({
  role: 'user',
  content: s.caller_transcript,
  language: s.detected_language
});

return [{ json: { ...s, memory: memory } }];

// ═══ EMOTION DETECTION ═══
const s = $input.first().json;
const text = s.caller_transcript || '';
const low = text.toLowerCase();

const anger = ['worst','terrible','disgusting','pathetic','waste','cheat','fraud','angry','disappointed','unacceptable','ridiculous','horrible','damn','hell','useless','stupid'];
const urgency = ['urgent','immediately','right now','emergency','asap','hurry','quickly','fast','tonight','today only','need now'];
const confusion = ['confused','don\'t understand','what do you mean','unclear','not sure','which one','huh','sorry what','come again','pardon'];
const happy = ['great','awesome','perfect','wonderful','amazing','excellent','fantastic','love it','thank you so much','brilliant'];
const escalate = ['manager','supervisor','human','real person','transfer','speak to someone','complaint','higher authority','your boss'];

let emotion = 'neutral';
let needsEsc = false;

if (escalate.some(k => low.includes(k))) { needsEsc = true; emotion = 'wants_escalation'; }
else if (anger.some(k => low.includes(k))) { emotion = 'angry'; }
else if (urgency.some(k => low.includes(k))) { emotion = 'urgent'; }
else if (confusion.some(k => low.includes(k))) { emotion = 'confused'; }
else if (happy.some(k => low.includes(k))) { emotion = 'happy'; }

return [{ json: { ...s, emotion: emotion, needs_escalation: needsEsc } }];

// ═══════════════════════════════════════════
// AI PROMPT BUILDER
// ═══════════════════════════════════════════
const s = $input.first().json;

const systemPrompt = `You are Priya, a warm, professional customer care executive at ${s.business_name || 'the venue'}.

IDENTITY: You are HUMAN. NEVER reveal you are AI. Your name is Priya.

LANGUAGE: Respond in ${s.language_name || 'English'}. If caller code-switches (Tanglish etc.), mirror their style. Use informal spoken style.

CURRENT EMOTION: ${s.emotion || 'neutral'}
- angry: Be calm, empathetic. "I'm sorry about that, let me fix this."
- urgent: Be quick, efficient. Skip pleasantries.
- confused: Be patient, step-by-step.
- happy: Match energy. Good for upselling.
- neutral: Warm, professional.

RULES:
- Keep responses 1-3 sentences. Ask ONE question at a time.
- Use fillers naturally: "Sure thing", "Got it", "Let me check"
- Use caller's name when known: ${s.caller_name || 'not yet known'}
- NEVER use bullet points or lists.

BUSINESS INFO:
- Name: ${s.business_name || 'N/A'}
- Timings: ${s.timings || 'N/A'}
- Menu: ${s.menu_highlights || 'N/A'}
- Offers: ${s.current_offers || 'N/A'}
- VIP: ${s.vip_options || 'N/A'}
- Address: ${s.address || 'N/A'}

INTENT HANDLING:
1. BOOKING: Collect date, time, guests, name. ONE per turn. Recap before confirming. Upsell VIP/events once.
2. ENQUIRY: Answer from business info. If unsure: "Let me check."
3. COMPLAINT: Listen, empathize, apologize, resolve. Escalate if needed.
4. GENERAL: Be friendly, brief. Steer to business.

DATA EXTRACTION (CRITICAL):
After EVERY response, on a new line, output:
<data>{"intent":"booking|enquiry|complaint|general","date":"YYYY-MM-DD or null","time":"HH:MM or null","guests":null,"name":null,"special_requests":null,"action_type":"continue|transfer|end_call|confirm_booking","action_number":null}</data>`;

const messages = [{ role: 'user', content: s.caller_transcript }];

return [{ json: { ...s, system_prompt: systemPrompt, ai_messages: messages } }];

// ═══ PARSE AI RESPONSE ═══
const input = $input.first().json;
let aiText = '';
try { aiText = input.content[0].text || ''; }
catch(e) { aiText = 'Sorry, could you repeat that?'; }

// Extract <data> block
let extracted = { intent: 'unknown', action_type: 'continue' };
const m = aiText.match(/<data>([\s\S]*?)<\/data>/);
if (m) { try { extracted = JSON.parse(m[1]); } catch(e) {} }

// Clean spoken text
const spoken = aiText.replace(/<data>[\s\S]*?<\/data>/g, '').trim();

// Build action object
const action = { type: extracted.action_type || 'continue' };
if (action.type === 'transfer') action.number = extracted.action_number || '';

// Build booking data
const booking = {};
if (extracted.date) booking.date = extracted.date;
if (extracted.time) booking.time = extracted.time;
if (extracted.guests) booking.guests = extracted.guests;
if (extracted.name) booking.name = extracted.name;
if (extracted.special_requests) booking.special_requests = extracted.special_requests;

const bookingComplete = extracted.intent === 'booking' &&
  extracted.date && extracted.time && extracted.guests && extracted.name;

if (bookingComplete) action.type = 'confirm_booking';

return [{ json: {
  reply_text: spoken,
  intent: extracted.intent || 'unknown',
  emotion: input.emotion || 'neutral',
  action: action,
  booking_data: booking,
  booking_complete: bookingComplete || false,
  session_id: input.session_id,
  business_id: input.business_id,
  caller_number: input.caller_number,
  detected_language: input.detected_language
}}];

// ═══ SAVE TO MEMORY ═══
// In production: write to Redis
// For now: pass through (memory is in the response)
const s = $input.first().json;

// Log this turn for analytics
console.log(`[TURN] session=${s.session_id} intent=${s.intent} emotion=${s.emotion} response="${s.reply_text.substring(0, 50)}..."`);

return [{ json: s }];
